(() => {
  type Row = { id: number; name: string; age: number };
  const columns: TableColumn<Row>[] = [
    { header: 'ID', accessor: 'id', align: 'right', sortable: true },
    { header: 'Name', accessor: 'name', sortable: true },
    { header: 'Age', accessor: 'age', align: 'right', sortable: true },
  ];
  const data: Row[] = [
    { id: 1, name: 'Katherine Johnson', age: 41 },
    { id: 2, name: 'Tim Berners‑Lee', age: 35 },
    { id: 3, name: 'Linus Torvalds', age: 29 },
  ];
  const Demo = () => {
    const [selected, setSelected] = React.useState<Row[]>([]);
    return (<Stack>
      <Panel fullWidth>
        <Table data={data} columns={columns} selectionMode='single' initialSort={{ index: 0 }} onSelectionChange={setSelected} />
