(() => {
  type Row = { id: number; name: string };
  const columns: TableColumn<Row>[] = [
    { header: 'ID', accessor: 'id', align: 'right' },
    { header: 'Name', accessor: 'name' },
  ];
  const seed: Row[] = [
    { id: 1, name: 'Ada Lovelace' },
    { id: 2, name: 'Alan Turing' },
    { id: 3, name: 'Grace Hopper' },
  ];
  const Demo = () => {
    const [data, setData] = React.useState<Row[]>(seed);
    const [selected, setSelected] = React.useState<Row[]>([]);
    // Immutable refresh: brand-new row objects, same ids. With getItemKey='id'
    // the current selection is preserved across the refresh.
    const refresh = () => setData((d) => d.map((r) => ({ ...r })));
    return (
      <Stack gap={2}>
        <Panel fullWidth>
          <Table data={data} columns={columns} selectionMode='multiple' getItemKey='id' onSelectionChange={setSelected} />
        </Panel>
        <Button onClick={refresh}>Refresh data</Button>
        <Typography variant='subtitle'>Selected: {selected.map((r) => r.id).join(', ') || '—'}</Typography>
      </Stack>
    );
  };
  return <Demo />;
})()

