    return (
      <Stack gap={2}>
        <Panel fullWidth>
          <Table data={data} columns={columns} selectionMode='multiple' getItemKey='id' selected={selected} onSelectionChange={setSelected} />
        </Panel>
        <Stack direction='row' gap={1}>
          <Button onClick={() => setSelected(data)}>Select all</Button>
          <Button onClick={() => setSelected([])}>Clear</Button>
        </Stack>
        <Typography variant='subtitle'>Selected: {selected.map((r) => r.id).join(', ') || '—'}</Typography>
      </Stack>
    );
  };
  return <Demo />;
})()

