(() => {
  type Invoice = { id: number; customer: string; total: number };
  const columns: TableColumn<Invoice>[] = [
    { header: 'Invoice', accessor: 'id', align: 'right' },
    { header: 'Customer', accessor: 'customer' },
    {
      header: 'Total',
      accessor: (row: Invoice) => `$${row.total.toFixed(2)}`,
      align: 'right',
    },
  ];
  const data: Invoice[] = [
    { id: 4821, customer: 'Juniper Labs', total: 8421.17 },
    { id: 4822, customer: 'Halo Forge', total: 311.25 },
    { id: 4823, customer: 'Even Tide', total: 1775.4 },
  ];
  const Demo = () => {
    const [lastClick, setLastClick] = React.useState<Invoice | null>(null);
    return (
      <Stack gap={2}>
        <Panel fullWidth>
          <Table
            data={data}
            columns={columns}
            hoverable
            onRowClick={(row) => setLastClick(row)}
          />
        </Panel>
        <Typography variant='subtitle'>
          Last clicked: {lastClick ? `${lastClick.customer} (#${lastClick.id})` : '—'}
        </Typography>
      </Stack>
    );
  };
  return <Demo />;
})()
